class Solution:
    def countOfAtoms(self, formula: str) -> str:
        stack = [{}]
        i = 0
        while i < len(formula):
            if formula[i] == '(':
                stack.append({})
                i += 1
            elif formula[i] == ')':
                top = stack.pop()
                i += 1
                while i < len(formula) and formula[i].isdigit():
                    i += 1
                if i < len(formula) and formula[i].isalpha():
                    i -= 1
                    while i >= 0 and not formula[i].isalpha():
                        i -= 1
                    name = formula[i+1:i+1+len(formula[i:i+1].lower())]
                    i += 1+len(formula[i:i+1].lower())
                    count = 1
                    while i < len(formula) and formula[i].isdigit():
                        count = count * 10 + int(formula[i])
                        i += 1
                    for k, v in top.items():
                        top[k] += v * count
                    if name in stack[-1]:
                        stack[-1][name] += top.get(name, 0)
                    else:
                        stack[-1][name] = top.get(name, 0)
            else:
                i += 1
        res = []
        for k, v in sorted(stack[0].items()):
            res.append(k)
            if v > 1:
                res.append(str(v))
        return ''.join(res)
